// Generated by scripts/build-content.mjs. Edit the source HTML in references/, then rebuild.
export const officialRulesHtml = "<h1>Jet Lag The Game: Hide and Seek</h1>\n      <div class=\"subtitle\">A transit game — find your friends</div>\n\n      <p>Jet Lag The Game: Hide and Seek is a modern version of classic hide and seek, where one player (the <i>hider</i>) uses public transit to hide somewhere in a city/region, and the other players (the <i>seekers</i>) must find them. The game combines strategic planning, exploration, and deductive reasoning.</p>\n\n      <h2 id=\"outline\">Overview</h2>\n      <ol>\n        <li>The game requires <b>at least two players</b>. The recommended maximum is 4 players.</li>\n        <li>The game consists of several rounds. In each round, one player becomes the <i>hider</i>, and the rest form the team of <i>seekers</i>.</li>\n        <li>At the start of the round, the hider has a <i>hiding period</i> during which they must use public transit to reach their <i>hiding zone</i>, <b>where they must remain for the rest of the round</b>.</li>\n        <li>During the round, <b>seekers move together around the game area</b> and <b>ask the hider questions about their location</b> to narrow down the search area.</li>\n        <li>Each time the hider answers a question, they <b>draw one or more cards from their hider deck</b>. These cards give them various advantages in the game.</li>\n        <li>Once the hider is found by the seekers, <b>the role passes to the next player</b>.</li>\n        <li>The winner is the player who <b>remained hidden the longest</b>.</li>\n      </ol>\n      <p>This is the general structure of the game. Each aspect of gameplay is described in more detail below.</p>\n\n      <h2 id=\"preparation\">Preparation</h2>\n      <p>Before starting the game, decide on the <b>players</b>, <b>game size</b>, <b>allowed transit types</b>, and <b>map boundaries</b>.</p>\n\n      <details>\n        <summary>Required Materials</summary>\n        <p>If you don't have the <a href=\"https://store.nebula.tv/products/hideandseek\" target=\"_blank\">printed version of the game</a>, we recommend each player use the following web tools:</p>\n        <ul>\n          <li>This rules page for resolving disputes</li>\n          <li><a href=\"https://taibeled.github.io/JetLagHideAndSeek/\" target=\"_blank\">Online map</a> (seekers: to ask questions; hider: to answer them)</li>\n          <li><a href=\"https://jetlag.denull.ru/\" target=\"_blank\">Online hider deck</a> (for the hider only)</li>\n          <li>Any service that <b>lets you share your live location</b>—for example, Apple Find My, Google Maps, or Telegram group location sharing.</li>\n        </ul>\n        <p>Also bring <b>4 dice</b> (2 for the hider, 2 for the seekers). Optionally, you can print a map of your chosen game area.</p>\n      </details>\n\n      <details>\n        <summary>Players and Teams</summary>\n        <p><b>We recommend playing with no more than 4 people</b>. If you have more, group them into teams that act as a single player.</p>\n        <p>Teams are also recommended for younger players or if a hider would feel unsafe being alone for a long time.</p>\n        <p><b>By default, the number of rounds equals the number of players</b>: each player should be the hider once. If you want to play longer, you can add extra rounds—in that case, each player's best round counts, not the sum.</p>\n      </details>\n\n      <details>\n        <summary>Game Size</summary>\n        <p>Some rules depend on the chosen game size—for example, card values and available questions. Game size options:</p>\n        <ul>\n          <li><b>Small (S)</b> — a single town or part of a large city.<br/>\n            <i>Duration:</i> 4-8 hours.<br/>\n            <i>Examples:</i> Lower Manhattan, a small city</li>\n          <li><b>Medium (M)</b> — a major city or metro area.<br/>\n            <i>Duration:</i> about a day.<br/>\n            <i>Examples:</i> Hong Kong, New York City, Greater London</li>\n          <li><b>Large (L)</b> — a region, country, or several countries.<br/>\n            <i>Duration:</i> 2-4 days.<br/>\n            <i>Examples:</i> Switzerland, Japan, New England</li>\n        </ul>\n      </details>\n\n      <details>\n        <summary>Transit System</summary>\n        <p><b>The local transit system is the backbone of the game</b>. While <a href=\"#experimental\">experimental formats</a> allow for cars or walking, we <b>strongly recommend using public transit</b>. Any type is fine—metro, trains, trams, buses, ferries, etc.—just agree on which are in play.</p>\n        <p><b>The center of the hider's zone must always be a station in the chosen transit system</b>, so make sure there are enough stations for a balanced game. If your city only has a few dozen metro stations, consider including bus stops.</p>\n        <p>Recommended number of stations for each game size:</p>\n        <ul>\n          <li><b>Small (S)</b> — 30–100 stations, 10–100 sq. miles</li>\n          <li><b>Medium (M)</b> — 100–500 stations, 100–1,000 sq. miles</li>\n          <li><b>Large (L)</b> — 500+ stations, 1,000+ sq. miles</li>\n        </ul>\n      </details>\n\n      <details>\n        <summary>Map Borders</summary>\n        <p>Set <b>clear, agreed-upon boundaries</b> for the game area. You decide if your game covers a neighborhood or a continent—<b>just make sure all players use the same borders</b>.</p>\n        <p><b>Also, make sure all players feel safe in all parts of the map</b>. Discuss safety in advance, and exclude any areas where someone would feel uncomfortable.</p>\n      </details>\n      \n      <details>\n        <summary>Rest Periods</summary>\n        <p>If your game will last multiple days, set rest periods at the end of each day. We recommend at least 10 hours so everyone can rest properly. All players should return to the same locations they were at when the rest period began.</p>\n      </details>\n\n      <h2 id=\"round-start\">Round Start</h2>\n      <p>In each round, one player (or team) is the <i>hider</i>, and the rest are the <i>seekers</i>. Decide the hiding order randomly before the game starts.</p>\n      <p>Make sure the hider has the hider deck (or <a href=\"https://jetlag.denull.ru\" target=\"_blank\">the online version</a>) and 2 dice. Seekers also need 2 dice.</p>\n      <p><b>Set up live location sharing for the seekers</b>, so the hider can see their movements during the round. Make sure the hider's location sharing is off.</p>\n      <p>Each round starts with a <b>hiding period</b>, during which the hider must reach any station within the game area (on foot or by transit). After the hiding period ends, and until the round ends, the hider must stay within their <a href=\"#hiding-zone\">hiding zone</a>.</p>\n      <p>Hiding period by game size:</p>\n      <ul>\n        <li><b>Small (S)</b> — 30 minutes</li>\n        <li><b>Medium (M)</b> — 60 minutes</li>\n        <li><b>Large (L)</b> — 180 minutes</li>\n      </ul>\n\n      <h2 id=\"hiding-zone\">Hiding Zone</h2>\n      <p>At the end of the <i>hiding period</i>, the hider must be at a station/stop in play. This station becomes the center of their <i>hiding zone</i>—a circle of a certain radius, within which the hider can move freely until the <a href=\"#endgame\"><b>end game</b></a> begins. There may be other stations in the zone, but one must be fixed as \"yours\" for the round—some questions will refer to it.</p>\n      <p>Zone radius by game size: <b>Small/Medium</b>: 1/4 mile (400m); <b>Large</b>: 1/2 mile (800m).</p>\n      <details>\n        <summary>Tips for the Hider</summary>\n        <p>Choosing the right hiding zone is the most important decision of your round. There's rarely a single right answer. Out-of-the-way locations can be harder to identify, but once seekers narrow it down, few nearby stations make it easier for them. Dense areas offer complexity but make it easier for seekers to move around.</p>\n        <p>While in your zone, you can do anything—shop, eat, walk in the park—but don't get too distracted. Many <b>Photo</b> questions require you to reach a spot in the zone quickly. You can take these photos in advance to save time. Also, spend some time finding your final <i>hiding spot</i>.</p>\n      </details>\n\n      <h2 id=\"questions\">Asking Questions</h2>\n      <p>To gather information about the hider's location, seekers must ask <a href=\"questions.html\"><b>various questions from six categories</b></a>. You can ask at any time—<b>as long as the previous question has been answered</b>. The hider must answer each question truthfully within <b>5 minutes</b> of receiving it. Exception: <b>Photo</b> questions—<b>10 minutes</b> in small/medium games, <b>20 minutes</b> in large games.</p>\n      <p>The hider may use the internet to answer—except <b>Google Street View</b> and similar services. This is the only strict research ban, but you can add your own rules if you wish.</p>\n      <p>After answering, the hider may draw and keep a certain number of cards from the <a href=\"#hider-deck\"><b>hider deck</b></a>—depending on the question category (see below).</p>\n      <details>\n        <summary>Additional Details</summary>\n        <p>The hider must make a reasonable effort to answer within the time limit. If they fail, their hiding timer pauses until they answer, and they do not draw cards for that question.</p>\n        <p>Once a question is asked, it cannot be asked again—unless seekers are willing to <b>pay its cost twice</b>. For example, if a question normally lets the hider draw 3 cards and keep 1, asking it again means the hider draws 3 and keeps 1, then draws 3 and keeps 1 again (not 6 and keep 2). Third time: pay the cost three times, and so on.</p>\n      </details>\n      <details>\n        <summary>About Mapping Apps</summary>\n        <p>You'll need a maps app on your phone or device. The game was designed with <a href=\"https://maps.google.com/\" target=\"_blank\"><b>Google Maps</b></a> in mind. Note: the <a href=\"https://taibeled.github.io/JetLagHideAndSeek/\" target=\"_blank\">online map for this game</a> uses OpenStreetMap data, so some places may differ from Google Maps. Apple Maps is better for rail visualization and sometimes has more accurate train schedules.</p>\n        <p>Many questions reference categories like parks, zoos, hospitals, museums, etc. These were chosen because they have special icons in Google Maps and Apple Maps. Amusement parks have a ferris wheel, libraries a book, etc. You can usually find all places in a category by searching and looking for these icons. Sometimes, though, there are categorization errors—a parking lot might be listed as an amusement park. Here's our rule:</p>\n        <ul>\n          <li><b>Google Maps:</b> Any place with 5+ reviews is legitimate unless all players agree otherwise. Fewer than 5 reviews: illegitimate unless all agree otherwise.</li>\n          <li><b>Other map apps:</b> Any place is legitimate unless all players agree otherwise.</li>\n        </ul>\n        <p><b>It's very important that the hider and seekers use the same maps app</b> when searching categories. Otherwise, you'll get different results and confusion.</p>\n        <b>In general, <b>seekers are responsible for clarifying any ambiguity in their questions</b>. For example, they can send a screenshot of all places they consider amusement parks when asking if the hider is near one.</b>\n      </details>\n\n      <h2 id=\"hider-deck\">The Hider Deck</h2>\n      <p>The hider deck contains three types of cards: <b>Time Bonus Cards</b>, <b>Powerup Cards</b>, and <b>Curse Cards</b>. The hider draws cards after answering a question, and keeps them until played or discarded.</p>\n      <p>For example, after answering a <b>Measuring</b> question, the hider draws 3 cards and keeps 1—draw the top 3 cards, keep 1, discard the rest. In the <a href=\"https://jetlag.denull.ru\" target=\"_blank\">online deck</a>, pull down to draw, up to discard/play.</p>\n      <p><b>The hider can hold up to 6 cards at once</b> (unless increased by a powerup). If they exceed this, they must immediately play or discard down to 6.</p>\n      <details>\n        <summary>Time Bonus Cards</summary>\n        <p>Time bonus cards have different values and count toward the hider's final hiding time. They cannot be \"played\"—only discarded. Time bonuses are added to the hider's time <b>only if they are in hand at the end of the round</b>; discarding one means you lose that bonus. Try to keep as many as possible at the end of the round. Time bonuses scale by game size—make sure you use the right value!</p>\n      </details>\n      <details>\n        <summary>Powerup Cards</summary>\n        <p>There are several types of powerups. They can be played at any time for a one-time advantage. Once played, discard them. Only inform seekers if the powerup directly affects them. Types include:</p>\n        <ul>\n          <li><b>Veto</b>: Play in response to a question instead of answering. Seekers get no answer and are told you used a veto. The question is still considered asked (can only be asked again for extra cost), but you do not draw cards. Play any time during the response window.</li>\n          <li><b>Randomize</b>: Play in response to a question instead of answering. Seekers must randomly choose a different unasked question from the same category (e.g., a 10 mile radar might become a 50 mile radar). That question is then asked instead, and you answer as normal. The original question is <b>not</b> considered asked. If the randomize causes a null answer, that's allowed. Play any time during the response window.</li>\n          <li><b>Discard 1, draw 2</b> and <b>Discard 2, draw 3</b>: Play any time. Discard unwanted cards to draw new ones. If you don't have enough cards to discard, you can't play these.</li>\n          <li><b>Draw 1, expand hand size by 1</b>: Play any time. Draw 1 card and increase your hand size by 1 for the rest of the round (up to 7, or 8 if played twice).</li>\n          <li><b>Duplicate</b>: Play as a copy of any other card in your hand. The original remains. If a duplicate is in hand at the end of the round, it can copy any time bonus, doubling that bonus.</li>\n          <li><b>Move</b>: Play to get time (by game size) to establish a <b>new hiding zone</b>. You must center on a new transit station, using only valid transit. While moving, your hiding timer pauses, and seekers must stay put and not ask questions. When time is up, resume play and your timer. After playing, <b>immediately discard your entire hand and tell seekers your original station</b>. Move cannot be played during the end game. Use wisely!</li>\n        </ul>\n      </details>\n      <details>\n        <summary>Curse Cards</summary>\n        <p>Curse cards are played against seekers to slow them down, prevent questions, or just annoy them. Each curse is unique and has a one-time effect. Once played, discard it.</p>\n        <p>Curses can't always be played at any time; each has a <b>casting cost</b>. Sometimes this is a resource (discarding cards), sometimes a game condition (e.g., seekers must be at least 10 miles away). Some costs vary by game size.</p>\n        <p>You can play multiple curses at once, <b>but never more than one curse that blocks questions or transit at a time</b>. Wait for a blocking curse to expire before playing another. Seekers must inform you when a curse is cleared.</p>\n        <p>For details on each curse, see the <a href=\"curses\">curses page</a>.</p>\n      </details>\n\n      <h2 id=\"endgame\">End Game</h2>\n      <p>Once the seekers <b>enter the hider's zone</b> and <b>leave transit</b>, the <b>end game</b> begins. The hider must now stay at a single, publicly accessible <b>hiding spot</b> until found.</p>\n      <p>Some questions become impossible to answer due to movement restrictions (e.g., a photo from a train station if not at a station). In these cases, \"I cannot answer the question\" is valid, and the hider draws cards as usual.</p>\n      <details>\n        <summary>Choosing a Hiding Spot</summary>\n        <p>Your hiding spot can be anywhere in your zone, but must be <b>publicly accessible at all game times</b> (except rest periods). You can't hide in a bathroom stall or someone's home. The spot doesn't have to be public property—just accessible. Make sure you won't be kicked out or draw suspicion. We recommend avoiding stores or businesses, even if open during the game.</p>\n        <p>Your spot must be <b>within 10 feet of a marked path or road on your map app</b>—no wandering into the wilderness or swimming out to sea. Seekers should be able to follow a route to within 10 feet of you.</p>\n        <p>Your spot is fixed the moment the end game begins. If you're not where you planned, wherever you are becomes your spot. If not publicly accessible, move to the nearest accessible spot immediately.</p>\n        <p>Spend time scouting your zone for the best spot. A good choice can buy you an extra hour or more, even after seekers find your station.</p>\n      </details>\n\n      <h2 id=\"round-change\">Rotating Rounds</h2>\n      <p>The hider is found when seekers <b>spot them and are within 5 feet</b>. If seekers are nearby but haven't identified the hider, they aren't caught yet. When caught, the hiding timer stops, and all time bonus cards in hand are added to the hider's total.</p>\n      <p>After the hider is caught, the next hider gets 10 minutes to prepare. During this time, they get the hider deck and turn off location sharing. The next round starts from the previous hider's spot.</p>\n\n      <h2 id=\"finale\">Ending the Game</h2>\n      <p>By default, the game ends after each player has been the hider the agreed number of times. <b>The player with the longest single hiding run is the winner</b>.</p>\n      <p>If you're playing with a time limit (e.g., a flight or work), set a game end timer. The game ends when either all rounds are finished or the timer runs out, whichever comes first.</p>\n\n      <h2 id=\"tips\">General Tips</h2>\n      <p>Hide and Seek is physically and mentally demanding. Especially for medium and large games, which can last days, <b>adequate preparation</b> is crucial. Here are some tips for staying healthy and comfortable:</p>\n      <details>\n        <summary>Tips List</summary>\n        <ul style=\"padding-inline-start: 1em\">\n          <li><b>Always pack enough food and water for at least one full day of gameplay</b>. As the hider, you may find yourself without access to food or water for hours. Use rest periods to restock.</li>\n          <li>Consider <b>weather in all parts of the game map</b> for all days you'll be playing. Pay special attention to mountains or areas prone to storms—you don't want to play soaking wet.</li>\n          <li><b>We highly recommend all players carry a portable battery</b> to charge phones. You'll use your phone often for research and communication, and it may not last a full day.</li>\n          <li>When choosing a hiding zone, make sure there's a <b>bathroom you can access</b> somewhere in the zone. Small stations and bus stops may not have bathrooms, so look for restaurants or stores that do.</li>\n          <li>If your game lasts more than a day (and you're far from home), check for hotels in your zone. You can <b>leave your zone during rest periods</b> to find a place to stay, but it's not recommended—rest is important!</li>\n          <li>You can <b>pause the game</b> if needed. Don't abuse this or use it for strategic advantage, but safety and comfort come first. When paused, all timers stop. When resumed, all players must be in the same spot as when paused.</li>\n          <li>As mentioned earlier, <b>make sure your map only includes areas where all players feel safe</b>. Discuss safety before playing and exclude any uncomfortable areas.</li>\n          <li>For safety, it's a good idea for the hider and seekers to <b>share their locations with a third party not playing the game</b>. If something unexpected happens—weather or health emergency—it's good for someone else to know where you are.</li>\n        </ul>\n      </details>\n\n      <h2 id=\"experimental\">Experimental Game Designs</h2>\n      <p>Earlier, we described the rules for standard Hide and Seek. The authors have also considered alternative versions, which we share here in case you want to try them—or use them as a starting point for your own mode!</p>\n      <details>\n        <summary>Playing with Cars (or on Foot)</summary>\n        <p>If your town doesn't have enough public transit for even a small game, you can adapt the rules for cars or walking. In this case, you'll need to make a few changes:</p>\n        <ul>\n          <li><b>Preparation</b>: Without a transit system, just set map borders. Draw them carefully, as it's easier to get confused about valid hiding spots.</li>\n          <li><b>Hiding Zones</b>: Still circles of varying radius. Instead of a transit station, use a <b>street terminus</b> (where a street ends at an intersection or dead end) as the center. This replaces the station for all purposes—photos, questions, etc.</li>\n          <li><b>Questions</b>: Most work as usual. Ignore any that reference transit frequency. Questions about the hider's station now refer to the street name.</li>\n          <li><b>Curses</b>: Any curse that can't be played while seekers are on transit also can't be played while they're in a moving car. Curses that block \"transportation\" or \"transit\" also block cars.</li>\n        </ul>\n      </details>\n      <details>\n        <summary>Two Teams of Seekers</summary>\n        <p>The authors liked the idea of two teams of seekers racing to find the same hider. For the show, this was too complex, but you might be able to make it work.</p>\n        <p>In this version, <b>winners are determined by seeking time, not hiding time</b>. This can be done by points or by lowest seeking time.</p>\n        <ul>\n          <li><b>Points:</b> Each round is worth <b>one point</b>. The team with the fastest seeking time gets the point. The hider is neutral—one team gets the point no matter what. The hider does not control the hider deck, but administers card draws for both teams. Teams can track and cast curses on each other, and time bonuses subtract from seeking time. Veto and randomize are removed from the deck. After each round, roles rotate, and one team becomes the hider for the next round.</li>\n          <li><b>Lowest seeking time:</b> The fastest time to find the hider in any round. Here, the hider <i>does</i> want to choose a hard spot and slow both teams, as they compete against their own hiding run. They control the hider deck and can cast curses on either team. Teams don't interact—no trackers, no way to slow each other. It's just a race.</li>\n        </ul>\n        <p>Most mechanics remain unchanged. Map setup and hiding zone rules are the same. If seekers control the hider deck, some curses must be removed or modified—especially those with costs based on distance to the hider. If you try this, we recommend writing some custom curses or powerups for seekers.</p>\n      </details>\n      <details>\n        <summary>Global Hide and Seek</summary>\n        <p>Should you do this? No. Will it work? Probably not. Will someone try anyway? Almost certainly! Here are some thoughts on how Hide and Seek could work globally.</p>\n        <p>You probably can't list all included transit networks, so set general criteria for valid stations (e.g., \"commercial airports with 100,000+ passengers/year\" and \"non-metro train stations\").</p>\n        <p>The time scale for large games won't work here. Use a new global scale: hiding rounds last 24 hours. Time bonuses, penalties, and limits are 5x large game values.</p>\n        <p>Most curses would need to be removed or replaced. Curses that slow seekers by distracting them (like the Cairn) are useless at this scale. You'll want new curses for the time and money involved—maybe a curse that sends seekers scuba diving for a shell, or forces them to climb a mountain or camp on an island.</p>\n        <p>You'll also need more questions in every category: add hemisphere, continent, and country to matching; equator and national capital to measuring; much larger radars; more thermometers; maybe a whole new tentacle category. All sorts of things.</p>\n        <p>There's <b>almost no way this game could be properly balanced</b>. Don't do it. Spend your money on something sensible. Put it in a mutual fund or something. Please don't do this. (But if you do, let us know. We're a little curious what happens.)</p>\n      </details>\n\n      <h2 id=\"glossary\">Glossary</h2>\n      <dl>\n        <dt>Hider</dt>\n        <dd>The player (or team) whose goal is to remain unfound by the seekers for as long as possible within their chosen hiding zone.</dd>\n        <dt>Seekers</dt>\n        <dd>All other players (except the hider), who move together around the game area, asking questions to find the hider.</dd>\n        <dt>Game Area</dt>\n        <dd>The region chosen by the players for the game. Agreed upon at the start and does not change during the game.</dd>\n        <dt>Hiding Zone</dt>\n        <dd>A circle of a certain radius around the hider's chosen station, within which they can move freely until the end game begins.</dd>\n        <dt>Hiding Spot</dt>\n        <dd>The specific place within the hiding zone where the hider must stay from the start of the end game until found by the seekers.</dd>\n        <dt>Hiding Period</dt>\n        <dd>The period at the start of each round during which the hider must reach their hiding zone.</dd>\n        <dt>Hiding Time</dt>\n        <dd>The time the hider spends in their hiding zone, from the end of the hiding period until found by the seekers. The timer pauses during rest periods and any force majeure events.</dd>\n        <dt>Seeker Questions</dt>\n        <dd>The 80 questions seekers can ask the hider about their location. The hider must answer truthfully and within the time limit.</dd>\n        <dt>Hider Deck</dt>\n        <dd>The set of cards from which the hider draws and keeps a certain number of cards for answering seeker questions. Contains time bonuses, powerups, and curses.</dd>\n        <dt>Time Bonus</dt>\n        <dd>Time added to the hider's hiding time, awarded as a time bonus card.</dd>\n        <dt>Powerup</dt>\n        <dd>A card that lets the hider take a special action for an advantage.</dd>\n        <dt>Curse</dt>\n        <dd>A card played by the hider to hinder the seekers or create extra challenges. Each curse has a cost the hider must pay to use it.</dd>\n        <dt>Rest Period</dt>\n        <dd>For multi-day games: a period at the end of each day for rest and recovery. All players must return to their locations from the start of the rest period.</dd>\n        <dt>End Game</dt>\n        <dd>The period at the end of a round when the hider can no longer move freely and must stay at their hiding spot.</dd>\n      </dl>";
